interface.definition:
a!localVariables(
  local!typeFilterSelection,
  local!initiatiorFilterSelection,
  local!names: {"Max Müller", "Karl Schmidt", "Peter Fischer", "Hans Becker", "Thomas Wagner", "Michael Braun", "Andreas Weber", "Stefan Hoffmann", "Markus Schäfer", "Frank Richter", "Juan García", "Ahmed Hassan", "Ivan Petrov", "Luigi Rossi", "Hiroshi Tanaka", "Pablo Fernández", "Ali Khan", "Sergei Ivanov", "Miguel Santos", "Omar Abdullah"},
  local!tasksPagingInfo: #"SYSTEM_SYSRULES_pagingInfo"(
    startIndex: 1,
    batchSize: 10,
    sort: #"SYSTEM_SYSRULES_sortInfo"(
      field: "c7",
      ascending: false
    )
  ),
  local!tasks: a!refreshVariable(
    value: a!queryProcessAnalytics(
      report: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1061067",
      query: #"SYSTEM_SYSRULES_query"(
        logicalExpression: #"SYSTEM_SYSRULES_queryLogicalExpression"(
          operator: "AND",
          ignoreFiltersWithEmptyValues: true,
          filters: {
            #"SYSTEM_SYSRULES_queryFilter"(
              field: "c1",
              operator: "=",
              value: local!initiatiorFilterSelection
            ),
            #"SYSTEM_SYSRULES_queryFilter"(
              field: "c11",
              operator: "=",
              value: local!typeFilterSelection
            ),
            #"SYSTEM_SYSRULES_queryFilter"(
              field: "c10",
              operator: "<>",
              value: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418982"
            )
          }
        ),
        pagingInfo: local!tasksPagingInfo
      )
    ),
    refreshInterval: 1,
    refreshAlways: true
  ),
  local!inmatesWithRequests: if(
    a!isNullOrEmpty(local!tasks.data),
    null,
    union(local!tasks.data.c1, local!tasks.data.c1)
  ),
  local!selectedInmate,
  local!sick: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1538358"(items: local!names, numberOfItemsToReturn: 2 + rand() * 3),
  local!out: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1538358"(items: difference(local!names, local!sick), numberOfItemsToReturn: 3 + rand() * 5),
  local!visits: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1538358"(items: difference(difference(local!names, local!sick), local!out), numberOfItemsToReturn: 5 + rand() * 3),
  #"SYSTEM_SYSRULES_headerContentLayout"(
    header: #"SYSTEM_SYSRULES_billboardLayout_v1"(
      backgroundMedia: #"SYSTEM_SYSRULES_documentImage"(document: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1069318"),
      backgroundColor: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1068602",
      height: "EXTRA_SHORT",
      marginBelow: "NONE",
      overlay: #"SYSTEM_SYSRULES_fullOverlay"(
        contents: {
          #"SYSTEM_SYSRULES_richTextDisplayField"(),
          #"SYSTEM_SYSRULES_sideBySideLayout"(
            items: {
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                  labelPosition: "COLLAPSED",
                  value: {
                    #"SYSTEM_SYSRULES_richTextItem_v1"(
                      text: {
                        #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1546843"(user: loggedInUser())
                      },
                      size: "LARGE"
                    )
                  }
                )
              ),
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                  labelPosition: "COLLAPSED",
                  value: {}
                )
              ),
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                  labelPosition: "COLLAPSED",
                  value: a!localVariables(
                    local!now: a!refreshVariable(
                      value: now(),
                      refreshInterval: 1
                    ),
                    #"SYSTEM_SYSRULES_richTextItem_v1"(
                      text: text(local!now, "dddd, dd. mmmm hh:mm"),
                      size: "LARGE"
                    )
                  )
                ),
                width: "MINIMIZE"
              ),
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_imageField_v1"(
                  labelPosition: "COLLAPSED",
                  images: #"SYSTEM_SYSRULES_documentImage"(
                    document: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1076413"
                  ),
                  size: "TINY",
                  align: "END"
                ),
                width: "MINIMIZE"
              )
            }
          )
        },
        style: "SEMI_DARK"
      )
    ),
    isHeaderFixed: true,
    contents: if(
      a!isNullOrEmpty(local!selectedInmate),
      {
        #"SYSTEM_SYSRULES_columnsLayout"(
          columns: {
            #"SYSTEM_SYSRULES_columnLayout"(
              contents: {
                /*Abwesenheit*/
                #"SYSTEM_SYSRULES_sectionLayout_v1"(
                  label: "Auf Krankenstation",
                  labelIcon: "ambulance",
                  labelColor: "STANDARD",
                  contents: {
                    #"SYSTEM_SYSRULES_forEach"(
                      items: local!sick,
                      expression: #"SYSTEM_SYSRULES_cardLayout"(
                        contents: {
                          #"SYSTEM_SYSRULES_richTextDisplayField"(
                            labelPosition: "COLLAPSED",
                            value: {
                              #"SYSTEM_SYSRULES_richTextItem_v1"(
                                text: fv!item,
                                style: "STRONG"
                              )
                            }
                          )
                        },
                        link: #"SYSTEM_SYSRULES_dynamicLink"(
                          value: fv!item,
                          saveInto: local!selectedInmate
                        ),
                        style: "STANDARD",
                        shape: "ROUNDED",
                        marginBelow: "LESS",
                        showBorder: false,
                        showShadow: true
                      )
                    )
                  }
                ),
                #"SYSTEM_SYSRULES_sectionLayout_v1"(
                  label: "Freigang",
                  labelIcon: "walking",
                  labelColor: "STANDARD",
                  contents: {
                    #"SYSTEM_SYSRULES_forEach"(
                      items: local!out,
                      expression: #"SYSTEM_SYSRULES_cardLayout"(
                        contents: {
                          #"SYSTEM_SYSRULES_richTextDisplayField"(
                            labelPosition: "COLLAPSED",
                            value: {
                              #"SYSTEM_SYSRULES_richTextItem_v1"(
                                text: fv!item,
                                style: "STRONG"
                              )
                            }
                          )
                        },
                        style: "STANDARD",
                        shape: "ROUNDED",
                        marginBelow: "LESS",
                        showBorder: false,
                        showShadow: true
                      )
                    )
                  }
                ),
                #"SYSTEM_SYSRULES_sectionLayout_v1"(
                  label: "Besuche",
                  labelIcon: "users",
                  labelColor: "STANDARD",
                  contents: {
                    #"SYSTEM_SYSRULES_forEach"(
                      items: local!visits,
                      expression: #"SYSTEM_SYSRULES_cardLayout"(
                        contents: {
                          #"SYSTEM_SYSRULES_richTextDisplayField"(
                            labelPosition: "COLLAPSED",
                            value: {
                              #"SYSTEM_SYSRULES_richTextItem_v1"(
                                text: fv!item,
                                style: "STRONG"
                              )
                            }
                          )
                        },
                        style: "STANDARD",
                        shape: "ROUNDED",
                        marginBelow: "LESS",
                        showBorder: false,
                        showShadow: true
                      )
                    )
                  }
                )
              },
              width: "NARROW_PLUS"
            ),
            #"SYSTEM_SYSRULES_columnLayout"(
              contents: {
                #"SYSTEM_SYSRULES_sectionLayout_v1"(
                  /* This is still hardcoded */
                  label: "Aufgaben",
                  labelIcon: "tasks-alt",
                  labelColor: "STANDARD",
                  contents: {
                    #"SYSTEM_SYSRULES_sideBySideLayout"(
                      items: {
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          item: #"SYSTEM_SYSRULES_dropdownField_v1"(
                            choiceLabels: #"SYSTEM_SYSRULES_forEach"(
                              items: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1693925"(),
                              expression: #"_a-0000ee50-153e-8000-88de-179188179188_15151"(taskTypeName: proper(substitute(fv!item, "_", " "))),
                            ),
                            choiceValues: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1693925"(),
                            label: #"urn:appian:translation-string:v1:b2c197a1-a03d-48e7-a776-d54d22c41ea5",
                            /* Turn into task tipe instead of request type */
                            placeholder: "-- " & #"urn:appian:translation-string:v1:1b5af186-ace6-4b27-a580-2ab17aa9b5be" & " --",
                            value: local!typeFilterSelection,
                            saveInto: local!typeFilterSelection
                          )
                        ),
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          item: #"SYSTEM_SYSRULES_dropdownField_v1"(
                            choiceLabels: #"SYSTEM_SYSRULES_forEach"(
                              items: local!inmatesWithRequests,
                              expression: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1535179"(userName: fv!item)
                            ),
                            choiceValues: local!inmatesWithRequests,
                            label: #"urn:appian:translation-string:v1:a5b5b659-bf28-444c-8e96-50fd2e142e09",
                            placeholder: "-- " & #"urn:appian:translation-string:v1:9f8c9573-6b20-4e0b-84af-0c40e449be25" & " --",
                            value: local!initiatiorFilterSelection,
                            saveInto: local!initiatiorFilterSelection
                          )
                        )
                      }
                    ),
                    /*Aufgabenliste*/
                    #"SYSTEM_SYSRULES_forEach"(
                      items: {
                        local!tasks.data
                      },
                      expression: #"SYSTEM_SYSRULES_cardLayout"(
                        contents: {
                          #"SYSTEM_SYSRULES_sideBySideLayout"(
                            items: {
                              #"SYSTEM_SYSRULES_sideBySideItem"(
                                item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                                  labelPosition: "COLLAPSED",
                                  value: {
                                    #"SYSTEM_SYSRULES_richTextItem_v1"(
                                      size: "MEDIUM_PLUS",
                                      text: fv!item.c0,
                                    ),
                                    char(10),
                                    #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1609689"(dateTime: fv!item.c2),
                                    " - ",
                                    #"SYSTEM_SYSRULES_richTextItem_v1"(
                                      text: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1609689"(dateTime: fv!item.c7),
                                      style: "STRONG"
                                    ),                                    
                                  }
                                )
                              ),
                              /*a!sideBySideItem(*/
                                /*item: a!richTextDisplayField(*/
                                  /*labelPosition: "COLLAPSED",*/
                                  /*value: a!richTextIcon(*/
                                    /*icon: if(*/
                                      /*now() > todatetime(fv!item.c7),*/
                                      /*"exclamation-circle",*/
                                      /*"clock"*/
                                    /*),*/
                                    /*color: if(*/
                                      /*now() > todatetime(fv!item.c7),*/
                                      /*"NEGATIVE",*/
                                      /*"STANDARD"*/
                                    /*),*/
                                    /*size: "LARGE"*/
                                  /*)*/
                                /*),*/
                                /*width: "MINIMIZE"*/
                              /*)*/
                            },
                            alignVertical: "MIDDLE"
                          )
                        },
                        link: #"SYSTEM_SYSRULES_processTaskLink"(
                          task: fv!item.dp0,
                          showWhen: a!isNotNullOrEmpty(fv!item.dp0)
                        ),
                        shape: "ROUNDED",
                        marginBelow: "STANDARD",
                        showBorder: false,
                        style: "STANDARD"
                      )
                    ),
                    #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1616691"(
                      pagingInfo: local!tasksPagingInfo,
                      saveInto: local!tasksPagingInfo,
                      totalCount: local!tasks.totalCount,
                      align: "CENTER"
                    )
                  }
                )
              },
              /*backgroundColor: "#85c47d"*/
            ),
            #"SYSTEM_SYSRULES_columnLayout"(
              contents: {
                #"SYSTEM_SYSRULES_recordActionField_v1"(
                  actions: {
                    #"SYSTEM_SYSRULES_recordActionItem"(
                      action: #"urn:appian:record-action:v1:fa952da3-a305-45ce-924b-89ca2dab3222/c9bf6c29-f136-4ecd-9006-6c13d140adbb"
                    )
                  },
                  style: "CALL_TO_ACTION",
                  display: "LABEL_AND_ICON",
                  align: "CENTER"
                ),
                #"SYSTEM_SYSRULES_horizontalLine"(),
                /*Bookmarks*/
                #"_a-0000ee50-153e-8000-88de-179188179188_17969"(
                  showWhen: true
                ),
                /*Allgemeine Hinweise*/
                #"SYSTEM_SYSRULES_sectionLayout_v1"(
                  label: "Hinweise",
                  labelIcon: "exclamation",
                  labelColor: "STANDARD",
                  contents: {
                    #"SYSTEM_SYSRULES_richTextDisplayField"(
                      label: "Stromausfall",
                      value: "Aufgrund eines Stromausfalls in Block B sind die Sicherheitskameras vorübergehend außer Betrieb. Bitte verstärken Sie die Überwachung in diesem Bereich."
                    ),
                    #"SYSTEM_SYSRULES_richTextDisplayField"(
                      label: "Krankheitsausbruch",
                      value: "Es wurde ein Krankheitsausbruch in Zellenblock C gemeldet. Stellen Sie sicher, dass alle betroffenen Insassen medizinisch versorgt werden und informieren Sie die Gesundheitsabteilung."
                    )
                  }
                ),

                /*Arbeitseinsätze*/
                #"SYSTEM_SYSRULES_sectionLayout_v1"(
                  label: "Arbeitseinsätze",
                  labelIcon: "tools",
                  labelColor: "STANDARD",
                  contents: {
                    #"SYSTEM_SYSRULES_richTextDisplayField"(
                      label: "Gartenarbeit",
                      value: "Die Insassen, die für die Gartenarbeit eingeteilt sind, treffen sich um 08:00 Uhr im Innenhof. Bitte stellen Sie sicher, dass alle benötigten Werkzeuge bereitstehen."
                    ),
                    #"SYSTEM_SYSRULES_richTextDisplayField"(
                      label: "Reinigungsdienst",
                      value: "Der Reinigungsdienst für die Gemeinschaftsbereiche beginnt um 09:00 Uhr. Weisen Sie die Insassen darauf hin, dass sie ihre zugewiesenen Bereiche gründlich reinigen."
                    ),
                    #"SYSTEM_SYSRULES_richTextDisplayField"(
                      label: "Werkstattarbeiten",
                      value: "Die Insassen, die in der Werkstatt arbeiten, werden heute an der Reparatur von Möbeln beteiligt sein. Bitte überprüfen Sie die Sicherheitsausrüstung und stellen Sie sicher, dass alle Insassen die Sicherheitsvorschriften einhalten."
                    )
                  }
                ),

                /*Speiseplan*/
                #"SYSTEM_SYSRULES_sectionLayout_v1"(
                  label: "Speiseplan",
                  labelIcon: "cutlery",
                  labelColor: "STANDARD",
                  contents: {
                    #"SYSTEM_SYSRULES_styledTextEditorField"(
                      labelPosition: "COLLAPSED",
                      value: "<h2>Montag</h2>
<ul>
<li><strong>Frühstück:</strong> Tee, Brot, Margarine, Nusspli</li>
<li><strong>Mittagessen:</strong> Bolognesesoße, Nudeln, Frischobst</li>
<li><strong>Abendessen:</strong> Tee, Brot, Margarine, gekochter Schinken</li>
</ul>
<h2>Dienstag</h2>
<ul>
<li><strong>Frühstück:</strong> Tee, Brot, Margarine, Nusspli</li>
<li><strong>Mittagessen:</strong> Möhreneintopf, falsches Kotelett</li>
<li><strong>Abendessen:</strong> Tee, Brot, Margarine, Putenleberwurst</li>
</ul>
<h2>Mittwoch</h2>
<ul>
<li><strong>Frühstück:</strong> Tee, Brot, Margarine, Nusspli</li>
<li><strong>Mittagessen:</strong> Spiegeleier, Kartoffelpüree, Spinat, Frischobst</li>
<li><strong>Abendessen:</strong> Tee, Brot, Margarine, Landkatenrauchwurst</li>
</ul>
<h2>Donnerstag</h2>
<ul>
<li><strong>Frühstück:</strong> Tee, Brot, Margarine, Jagdwurst</li>
<li><strong>Mittagessen:</strong> Gefüllte Paprika, Reis, Salat</li>
<li><strong>Abendessen:</strong> Tee, Brot, Margarine, Quark mit Brombeeren</li>
</ul>
<h2>Freitag</h2>
<ul>
<li><strong>Frühstück:</strong> Tee, Brot, Margarine, Nusspli</li>
<li><strong>Mittagessen:</strong> Bratfisch, Kartoffeln, Weißkohlsalat</li>
<li><strong>Abendessen:</strong> Tee, Brot, Margarine, Hering in Dosen</li>
</ul>
<h2>Samstag</h2>
<ul>
<li><strong>Frühstück:</strong> Kakao, Brot, Margarine, Edamer</li>
<li><strong>Mittagessen:</strong> Erbsensuppe, Bockwurst, Obst, Joghurt</li>
<li><strong>Abendessen:</strong> Tee, Brot, Margarine, Dosenwurst</li>
</ul>
<h2>Sonntag</h2>
<ul>
<li><strong>Frühstück:</strong> Tee, Brot, Margarine, Quarkbecher</li>
<li><strong>Mittagessen:</strong> Schweinebraten, Kartoffeln, Kaisergemüse, Dessert</li>
<li><strong>Abendessen:</strong> Tee, Brot, Margarine, Camembert</li>
</ul>",
                      sizeLimit: 4000,
                      readOnly: true
                    )
                  },
                  isCollapsible: true,
                  isInitiallyCollapsed: true
                )
              },
              width: "NARROW_PLUS",
            )
          }
        ),
        #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1531272"(showContact: true)
      },

      /* Inmate Details */
      #"SYSTEM_SYSRULES_cardLayout"(
        contents: {
          #"SYSTEM_SYSRULES_sideBySideLayout"(
            items: {
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                  labelPosition: "COLLAPSED",
                  value: {
                    #"SYSTEM_SYSRULES_richTextItem_v1"(
                      text: local!selectedInmate,
                      size: "LARGE",
                      style: "STRONG"
                    )
                  }
                )
              ),
              #"SYSTEM_SYSRULES_sideBySideItem"(
                item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                  labelPosition: "COLLAPSED",
                  value: {
                    #"SYSTEM_SYSRULES_richTextIcon"(
                      icon: "times",
                      link: #"SYSTEM_SYSRULES_dynamicLink"(
                        value: null,
                        saveInto: local!selectedInmate
                      ),
                      linkStyle: "STANDALONE",
                      size: "MEDIUM_PLUS"
                    )
                  }
                ),
                width: "MINIMIZE"
              )
            }
          ),
          #"SYSTEM_SYSRULES_columnsLayout"(
            columns: {
              #"SYSTEM_SYSRULES_columnLayout"(
                contents: {
                  #"SYSTEM_SYSRULES_columnsLayout"(
                    columns: {
                      #"SYSTEM_SYSRULES_columnLayout"(
                        contents: {
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Geburtsdatum",
                            labelPosition: "JUSTIFIED",
                            value: "15. April 1985",
                            readOnly: true
                          ),
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Geschlecht",
                            labelPosition: "JUSTIFIED",
                            value: "Männlich",
                            readOnly: true
                          ),
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Häftlingsnummer",
                            labelPosition: "JUSTIFIED",
                            value: "123456",
                            readOnly: true
                          ),
                          #"SYSTEM_SYSRULES_horizontalLine"(),
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Eintrittsdatum",
                            labelPosition: "JUSTIFIED",
                            value: "1. Januar 2025",
                            readOnly: true
                          ),
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Haftdauer",
                            labelPosition: "JUSTIFIED",
                            value: "5 Jahre",
                            readOnly: true
                          ),
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Entlassungsdatum",
                            labelPosition: "JUSTIFIED",
                            value: "31. Dezember 2029",
                            readOnly: true
                          ),
                          #"SYSTEM_SYSRULES_horizontalLine"(),
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Straftat",
                            labelPosition: "JUSTIFIED",
                            value: "Diebstahl",
                            readOnly: true
                          ),
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Verurteilendes Gericht",
                            labelPosition: "JUSTIFIED",
                            value: "Landgericht Köln",
                            readOnly: true
                          ),
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Verteidiger",
                            labelPosition: "JUSTIFIED",
                            value: "Dr. Anna Schmidt",
                            readOnly: true
                          ),
                          #"SYSTEM_SYSRULES_horizontalLine"(),
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Zellenblock",
                            labelPosition: "JUSTIFIED",
                            value: "B",
                            readOnly: true
                          ),
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Stockwerk",
                            labelPosition: "JUSTIFIED",
                            value: "2",
                            readOnly: true
                          ),
                          #"SYSTEM_SYSRULES_textField"(
                            label: "Zelle",
                            labelPosition: "JUSTIFIED",
                            value: "205",
                            readOnly: true
                          )
                        }
                      ),
                      #"SYSTEM_SYSRULES_columnLayout"(
                        contents: {
                          #"SYSTEM_SYSRULES_styledTextEditorField"(
                            labelPosition: "COLLAPSED",
                            value: "<strong>Gesundheitszustand</strong>
                              <ul>
                              <li><strong>Allgemein:</strong> Gut</li>
                              <li><strong>Chronische Erkrankungen:</strong> Keine</li>
                              <li><strong>Medikamente:</strong> Keine</li>
                              </ul>

                              <strong>Verhalten</strong>
                              <ul>
                              <li><strong>Disziplinarische Vorfälle:</strong> Keine</li>
                              <li><strong>Teilnahme an Rehabilitationsprogrammen:</strong> Ja (Berufsausbildung, Anti-Aggressions-Training)</li>
                              </ul>

                              <strong>Besucher</strong>
                              <ul>
                              <li><strong>Letzter Besuch:</strong> 20. Februar 2025 (Familie)</li>
                              <li><strong>Besuchshäufigkeit:</strong> Monatlich</li>
                              </ul>

                              <strong>Arbeitseinsatz</strong>
                              <ul>
                              <li><strong>Aktuelle Tätigkeit:</strong> Küchenhilfe</li>
                              <li><strong>Arbeitszeiten:</strong> 08:00 - 12:00 Uhr</li>
                              </ul>",
                            sizeLimit: 4000,
                            readOnly: true
                          )
                        }
                      )
                    }
                  )
                }
              ),
              #"SYSTEM_SYSRULES_columnLayout"(
                contents: {
                  #"SYSTEM_SYSRULES_imageField_v1"(
                    label: "Image",
                    labelPosition: "COLLAPSED",
                    images: #"SYSTEM_SYSRULES_documentImage"(document: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1074606"),
                    size: "FIT",
                    isThumbnail: true,
                    style: "STANDARD"
                  )
                },
                width: "MEDIUM"
              )
            }
          )


        },
        style: "#85c47d",
        shape: "ROUNDED",
        showBorder: false,
        showShadow: true
      )
    )
  )
)
